import{_ as n,o as r,c as o,a3 as t}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"13A. Performance Management","description":"","frontmatter":{"title":"13A. Performance Management","eba":"Doctors in Training 2022-2026","topics":["discipline"]},"headers":[],"relativePath":"ebas/doctors-in-training/consultation-disputes/13A-performance-management.md","filePath":"ebas/doctors-in-training/consultation-disputes/13A-performance-management.md"}'),a={name:"ebas/doctors-in-training/consultation-disputes/13A-performance-management.md"};function s(i,e,p,c,l,m){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="_13a-performance-management" tabindex="-1">13A. Performance Management <a class="header-anchor" href="#_13a-performance-management" aria-label="Permalink to &quot;13A. Performance Management&quot;">​</a></h1><p><strong>13A.1</strong> Purpose</p><p><strong>(a)</strong> Regular feedback and review that is proactive, informed and constructive is an important part of professional development for Doctors based on a shared commitment requiring good communication between the Doctor and the Supervisor / line manager.</p><p><strong>(b)</strong> The purpose of this clause is to ensure that where the Health Service or supervisor/line manager has concerns as to possible underperformance which need to be managed beyond any regular feedback or review process, they are addressed in manner that is structured, transparent and fair.</p><p><strong>(c)</strong> Whether through regular feedback and review or, in the case of possible underperformance, performance management; feedback should enable Doctors to optimise performance and communication and minimise unexpected feedback at the conclusion of a rotation through a reference</p><p><strong>(d)</strong> Doctors includes those that are not part of a formal training program.</p><p><strong>13A.2</strong> Application of this clause</p><p><strong>(a)</strong> Where an Employer wishes to deal with performance issues of a Doctor, they will be dealt with in accordance with this clause 13A..</p><p><strong>(b)</strong> Where an Employer has concerns about a performance issue that may constitute misconduct, they will be dealt with in accordance with clause 13B (Discipline). Where this occurs, the performance management process in subclauses 13A.4(c),</p><p><strong>(d)</strong> and (e) will still apply where appropriate.</p><p><strong>13A.3</strong> Informal</p><p>Where the Employer or the Employee has concerns about an Employee’s performance, the Employer will, wherever appropriate, deal with these concerns through informal discussions with the Employee when these concerns first arise. The Employer will clearly outline the concerns. The Employee will be given a reasonable opportunity to address the performance concerns</p><p><strong>13A.4</strong> Formal</p><p><strong>(a)</strong> Where the Employee’s work performance is not at an acceptable standard following the process in subclause 13A.2 or it was not appropriate to deal with the concerns informally, the Employer may initiate a formal performance management process.</p><p><strong>(b)</strong> The Employer will provide to the Employee in writing:</p><p><strong>(i)</strong> details of the performance concerns including, where relevant, material that supports those concerns; and</p><p><strong>(ii)</strong> notice of the Employee’s right to be represented by a Union or other representative.</p><p><strong>(c)</strong> The Employer will:</p><p><strong>(i)</strong> meet with the Employee and, where relevant, the Employee’s representative, to discuss the concerns;</p><p><strong>(ii)</strong> ensure the Employee is provided with a reasonable opportunity to answer any concerns including a reasonable time to respond;</p><p><strong>(iii)</strong> give genuine consideration to any response or matters raised by an Employee’s response; and</p><p><strong>(iv)</strong> if a performance management plan is proposed, consult with the Employee and the Employee’s representative on the content of the plan.</p><p><strong>(d)</strong> Where, having considered the Employee’s response, the Employer reasonably believes, based on the Employee’s performance, that a performance management plan is appropriate, the Employer will:</p><p><strong>(i)</strong> provide the performance management plan to the Employee in writing following the consultation referred to at subclause 13A.4(c)(iv) above, identifying which aspects of the Employee’s performance are unsatisfactory and the required level of performance which must be reasonable; and</p><p><strong>(ii)</strong> provide the Employee with a reasonable opportunity to address any concerns over a reasonable time.</p><p><strong>(e)</strong> The Employer will provide ongoing feedback on the Employee’s performance during this period, including if the Employee’s performance is not improving to a satisfactory standard, and will provide the Employee with all reasonable support, counselling and training.</p><p>Plain language terms: performance review, PIP.</p>',27)])])}const g=n(a,[["render",s]]);export{d as __pageData,g as default};
